#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int H, M;
        scanf("%d %d", &H, &M);
        int h1, m1, s1, sn1, sd1;
        scanf("%d %d %d %d %d", &h1, &m1, &s1, &sn1, &sd1);
        int h2, m2, s2, sn2, sd2;
        scanf("%d %d %d %d %d", &h2, &m2, &s2, &sn2, &sd2);
        int start = h1 * M * 60 + m1 * 60 + s1 + sn1 * 60 / sd1;
        int finish = h2 * M * 60 + m2 * 60 + s2 + sn2 * 60 / sd2;
        int count = 0;
        for (int i = start; i <= finish; i++) {
            int hour = i / (M * 60);
            int minute = (i % (M * 60)) / 60;
            int second = i % 60;
            if (hour < H && minute < M && hour * M + minute == minute * H + hour) {
                count++;
            }
        }
        printf("Case %d: %d\n", t + 1, count);
    }
    return 0;
}

