for (let t = 0; t < T; t++) {
    const [H, M] = readline().split(' ').map(Number);
    const [h1, m1, s1, sn1, sd1] = readline().split(' ').map(Number);
    const [h2, m2, s2, sn2, sd2] = readline().split(' ').map(Number);
    const start = h1 * M * 60 + m1 * 60 + s1 + Math.floor(sn1 * 60 / sd1);
    const finish = h2 * M * 60 + m2 * 60 + s2 + Math.floor(sn2 * 60 / sd2);
    let count = 0;
    for (let i = start; i <= finish; i++) {
        const hour = Math.floor(i / (M * 60));
        const minute = Math.floor((i % (M * 60)) / 60);
        const second = i % 60;
        if (hour < H && minute < M && hour * M + minute === minute * H + hour) {
            count++;
        }
    }
    console.log(`Case ${t + 1}: ${count}`);
}
